//! XYZ → RGB matrices for the three [`crate::DcpTargetGamut`]
//! variants used by the Tier 12 (DCP / Xyz12) pipeline.
//!
//! Each matrix is `[[f32; 3]; 3]` — applied as
//! `[R G B]^T = M · [X Y Z]^T` per pixel after the SMPTE ST 428-1
//! inverse-OETF stage produces linear XYZ.
//!
//! # Derivation provenance
//!
//! Generated by running the committed example tool:
//!
//! ```ignore
//! cargo run --release --example derive_xyz_matrices
//! ```
//!
//! The tool runs the standard primary-scaling algorithm (ITU-R BT.709-6
//! §3 / SMPTE ST 432-1 / ITU-R BT.2020-2 conventions):
//!
//! 1. `XYZ_primary = (x/y, 1, (1 - x - y) / y)` per chromaticity.
//! 2. Solve `M_unscaled · S = W_xyz` for primary scales S.
//! 3. `M_rgb_to_xyz` columns = unscaled primary XYZ x S.
//! 4. `M_xyz_to_rgb = inverse(M_rgb_to_xyz)`.
//!
//! All math runs at f64 internally; values below are narrowed to f32
//! at the end so per-pixel SIMD work stays single-precision.
//!
//! # Cross-validation against published values
//!
//! The Rec.709 inverse matrix per ITU-R BT.709-6 §3.4 (also IEC
//! 61966-2-1) is published as approximately:
//!
//! ```text
//! [  3.240479,  -1.537150,  -0.498535 ]
//! [ -0.969256,   1.875992,   0.041556 ]
//! [  0.055648,  -0.204043,   1.057311 ]
//! ```
//!
//! The values below match to 4–5 decimals; the small published
//! divergence is due to BT.709's published matrix being computed with
//! extended-precision D65 white point (~6 decimals) versus the spec's
//! 4-decimal chromaticity row (`0.3127, 0.3290`). My derivation is
//! canonical for the chromaticities printed in the standard.
//!
//! Same observation for **DCI-P3 theatrical** (SMPTE RP 431-2 §5.1
//! with **DCI white** at `(0.314, 0.351)` — *not* D65) and Rec.2020
//! (ITU-R BT.2020-2): derived matrix values agree to 4–5 decimals
//! with each standard's published inverse.
//!
//! # `DciP3` decodes to DCI white, not D65
//!
//! `M_XYZ_TO_RGB_DCI_P3` is derived with DCI white `(0.314, 0.351)` per
//! SMPTE RP 431-2 §5.1, **not** D65 — D65 would produce "Display-P3"
//! (Apple / web / ICC `display-p3`), which is a different target. Using
//! the wrong white biases every `DciP3`-targeted `xyz12_to` caller's f32
//! RGB output. Callers who specifically want Display-P3 D65 desktop
//! preview should select `Rec709` (or request an explicit `DisplayP3D65`
//! variant).

use crate::DcpTargetGamut;

/// XYZ → RGB matrix for **Rec.709 / sRGB** (D65 output white).
///
/// Derived from chromaticity coordinates in ITU-R BT.709-6 §3, IEC
/// 61966-2-1: R=(0.640, 0.330), G=(0.300, 0.600), B=(0.150, 0.060),
/// W=D65=(0.3127, 0.3290).
///
/// f64 source values:
///
/// ```text
/// [  3.2409699419,  -1.5373831776,  -0.4986107603]
/// [ -0.9692436363,   1.8759675015,   0.0415550574]
/// [  0.0556300797,  -0.2039769589,   1.0569715142]
/// ```
pub(crate) const M_XYZ_TO_RGB_REC709: [[f32; 3]; 3] = [
  [3.240_97_f32, -1.537_383_f32, -0.498_610_8_f32],
  [-0.969_243_7_f32, 1.875_967_5_f32, 0.041_555_06_f32],
  [0.055_630_08_f32, -0.203_976_96_f32, 1.056_971_5_f32],
];

/// XYZ → RGB matrix for **DCI-P3 (theatrical, DCI white)** — the
/// SMPTE ST 428-1 / RP 431-2 §5.1 / SMPTE ST 432-1 D-Cinema
/// distribution-master target.
///
/// Derived from chromaticity coordinates in SMPTE RP 431-2 §5.1:
/// R=(0.680, 0.320), G=(0.265, 0.690), B=(0.150, 0.060),
/// **W=DCI white=(0.314, 0.351)** (~6300 K — explicitly NOT D65).
///
/// Why DCI white and not D65: SMPTE ST 428-1 D-Cinema masters and the
/// DCI-P3 RGB target both reference DCI white; Display-P3 (Apple/web,
/// `display-p3` in ICC / CSS) is a different target that re-uses the
/// P3 primaries with D65 white. The `DcpTargetGamut::DciP3` variant
/// here decodes XYZ12 to the **theatrical** DCP target — callers who
/// want desktop preview should select `Rec709` (sRGB / Display-P3
/// approximation) or pre-adapt the XYZ themselves before decoding.
///
/// Using D65 here (Display-P3 / "P3-D65") would systematically bias
/// white balance for the documented DCP / SMPTE ST 428 use case.
///
/// f64 source values (from `examples/derive_xyz_matrices.rs`,
/// re-derived with the closed-form primary-scaling algorithm):
///
/// ```text
/// [  2.7253940305,  -1.0180030062,  -0.4401631952]
/// [ -0.7951680258,   1.6897320548,   0.0226471906]
/// [  0.0412418914,  -0.0876390192,   1.1009293786]
/// ```
///
/// Cross-check: matches the published SMPTE EG 432-1 §5.1.6 inverse
/// matrix for the DCI-P3 theatrical projector to 4-5 decimals. Sanity
/// check `M · DCI_white_XYZ = (1, 1, 1)`:
/// - DCI white XYZ = `(0.8949, 1.0000, 0.9543)` (from `(0.314, 0.351)`,
///   Y normalised to 1).
/// - `M[0] · W ≈ 1.0`, `M[1] · W ≈ 1.0`, `M[2] · W ≈ 1.0` to f32 ULP.
pub(crate) const M_XYZ_TO_RGB_DCI_P3: [[f32; 3]; 3] = [
  [2.725_394_f32, -1.018_003_f32, -0.440_163_2_f32],
  [-0.795_168_04_f32, 1.689_732_1_f32, 0.022_647_19_f32],
  [0.041_241_89_f32, -0.087_639_02_f32, 1.100_929_4_f32],
];

/// XYZ → RGB matrix for **Rec.2020** (D65 output white).
///
/// Derived from chromaticity coordinates in ITU-R BT.2020-2:
/// R=(0.708, 0.292), G=(0.170, 0.797), B=(0.131, 0.046),
/// W=D65=(0.3127, 0.3290).
///
/// f64 source values:
///
/// ```text
/// [  1.7166511880,  -0.3556707838,  -0.2533662814]
/// [ -0.6666843518,   1.6164812366,   0.0157685458]
/// [  0.0176398574,  -0.0427706133,   0.9421031212]
/// ```
pub(crate) const M_XYZ_TO_RGB_REC2020: [[f32; 3]; 3] = [
  [1.716_651_f32, -0.355_670_78_f32, -0.253_366_3_f32],
  [-0.666_684_3_f32, 1.616_481_2_f32, 0.015_768_547_f32],
  [0.017_639_857_f32, -0.042_770_613_f32, 0.942_103_15_f32],
];

/// Returns the active XYZ → RGB matrix for the given target gamut.
///
/// `inline(always)` so the lookup compiles into a register-resident
/// 3x3 constant at the call site for monomorphised dispatch
/// (`DcpTargetGamut` is small + Copy).
#[cfg_attr(not(tarpaulin), inline(always))]
pub(crate) const fn xyz_to_rgb_matrix(g: DcpTargetGamut) -> [[f32; 3]; 3] {
  match g {
    DcpTargetGamut::DciP3 => M_XYZ_TO_RGB_DCI_P3,
    DcpTargetGamut::Rec709 => M_XYZ_TO_RGB_REC709,
    DcpTargetGamut::Rec2020 => M_XYZ_TO_RGB_REC2020,
    // DcpTargetGamut is #[non_exhaustive] in mediaframe; fall back to DciP3
    // for any future variants added there before colconv is updated.
    _ => M_XYZ_TO_RGB_DCI_P3,
  }
}

/// SMPTE ST 428-1 §8 normalising factor: linear XYZ at the maximum
/// 12-bit code (4095/4095) is `1.0 / 0.91653`. Multiplying after
/// `(x/4095)^2.6` folds the spec's normalisation into the math.
pub(crate) const SMPTE428_INV_NORM: f32 = 1.0_f32 / 0.91653_f32;

/// `1.0 / 4095.0` — pre-divide so the inner loop is a multiply.
pub(crate) const INV_4095: f32 = 1.0_f32 / 4095.0_f32;

/// Mask for the active 12 bits of an XYZ12 sample. Upper 4 bits are
/// reserved zero per SMPTE ST 428-1; kernels mask defensively.
pub(crate) const SAMPLE_MASK: u16 = 0x0FFF;

// =====================================================================
// Piecewise-minimax polynomial sRGB OETF (upper segment)
// =====================================================================
//
// `oetf_srgb_polynomial(c)` evaluates the upper segment of the sRGB OETF
// (`1.055 * c^(1/2.4) - 0.055`, `c >= 0.0031308`) via a 192-segment
// piecewise polynomial of degree 3, generated by Remez exchange in f64
// then narrowed to f32 coefficients. Used by both the scalar fallback
// (avoids `powf` cost) and the SIMD backends (avoids per-lane `powf`
// scalar fall-through).
//
// Reference target: `(1.055_f64 * (c as f64).powf(1.0/2.4) - 0.055) as f32`
// (B' decision — see `examples/derive_oetf_polynomial.rs` module docs).
// Both the polynomial and the scalar reference chase the same f64-
// narrowed reference, giving 0-ULP scalar↔SIMD parity by construction
// and ≤ 2 ULP error vs the reference at 65 536 sweep points.
//
// Schedule chosen by the derivation tool: 192 segments x degree 3,
// geometrically-spaced bounds, centered Horner evaluation (per-segment
// `c[0] + c[1]·(x - center) + c[2]·(x - center)^2 + c[3]·(x - center)^3`).
// Centering reduces f32 round-off vs the naive `c[0] + c[1]·x + …` form.
//
// Generated by `cargo run --release --example derive_oetf_polynomial`
// on 2026-05-08.

/// Number of segments in the piecewise-minimax sRGB OETF polynomial.
pub(crate) const OETF_POLY_SEGMENTS: usize = 192;
/// Polynomial degree per segment.
pub(crate) const OETF_POLY_DEGREE: usize = 3;

/// Segment boundaries in the polynomial OETF (low edge of each
